<template>
  <div 
    class="glass-effect rounded-2xl p-6 hover:scale-105 transition-transform duration-300 cursor-pointer"
    @click="handleClick"
  >
    <!-- 项目头 -->
    <div class="flex items-start justify-between mb-4">
      <div>
        <h3 class="text-xl font-bold mb-2">{{ project.title }}</h3>
        <div class="flex items-center space-x-2">
          <span class="text-xs px-2 py-1 rounded-full" :class="statusColor">
            {{ project.status }}
          </span>
        </div>
      </div>
      <div class="w-10 h-10 rounded-lg bg-gradient-to-br" :class="project.color" />
    </div>

    <!-- 描述 -->
    <p class="text-gray-300 mb-6">{{ project.description }}</p>

    <!-- 技术栈 -->
    <div class="mb-6">
      <div class="flex flex-wrap gap-2">
        <span 
          v-for="tech in project.technologies"
          :key="tech"
          class="text-xs px-3 py-1 rounded-full glass-effect"
        >
          {{ tech }}
        </span>
      </div>
    </div>

    <!-- 操作按钮 -->
    <div class="flex space-x-3">
      <span class="text-sm font-semibold flex items-center text-indigo-400">
        查看详情
        <svg class="w-4 h-4 ml-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 7l5 5m0 0l-5 5m5-5H6"/>
        </svg>
      </span>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from 'vue'
import { useRouter } from 'vue-router'

const props = defineProps<{
  project: {
    title: string
    description: string
    technologies: string[]
    status: string
    color: string
    link?: string
    developing?: boolean
  }
}>()

const emit = defineEmits<{
  (e: 'developing-click', title: string): void
}>()

const router = useRouter()

const statusColor = computed(() => {
  const status = props.project.status
  if (status === '已完成') return 'bg-green-500/20 text-green-400'
  if (status === '进行中') return 'bg-blue-500/20 text-blue-400'
  if (status === '规划中') return 'bg-yellow-500/20 text-yellow-400'
  return 'bg-gray-500/20 text-gray-400'
})

const handleClick = () => {
  if (props.project.link) {
    router.push(props.project.link)
  } else if (props.project.developing) {
    emit('developing-click', props.project.title)
  }
}
</script>
